import React, { useState, useEffect } from "react";

const COLORS = {
  red: "#B80000",
  gold: "#D4A017",
  white: "#FFFFFF",
  lightGray: "#F4F4F4",
  darkText: "#222222",
  low: "#2E7D32", // verde
  medium: "#F9A825", // amarillo
  high: "#C62828", // rojo
};

const INCIDENT_TYPES = [
  "Basura acumulada",
  "Lote abandonado",
  "Daño en vía pública",
  "Alumbrado defectuoso",
  "Riesgo para peatones",
  "Otro",
];

const PRIORITY_OPTIONS = [
  { value: "baja", label: "Baja" },
  { value: "media", label: "Media" },
  { value: "alta", label: "Alta" },
  { value: "critica", label: "Crítica" },
];

const API_URL = "http://localhost:5000/api/reports";

function formatDate(isoString) {
  if (!isoString) return "";
  return new Date(isoString).toLocaleString("es-PA");
}

function getPriorityColor(priority) {
  switch (priority) {
    case "alta":
    case "critica":
      return COLORS.high;
    case "baja":
      return COLORS.low;
    default:
      return COLORS.medium;
  }
}

function getPriorityLabel(priority) {
  const found = PRIORITY_OPTIONS.find((p) => p.value === priority);
  return found ? found.label : "Media";
}

function App() {
  const [view, setView] = useState("home");
  const [reports, setReports] = useState([]);
  const [loadingReports, setLoadingReports] = useState(false);
  const [formLoading, setFormLoading] = useState(false);

  const [formData, setFormData] = useState({
    type: "",
    description: "",
    location: "",
    contact: "",
    priority: "media",
    zone: "",
  });

  // Cargar reportes desde el backend
  useEffect(() => {
    const fetchReports = async () => {
      try {
        setLoadingReports(true);
        const res = await fetch(API_URL);
        if (!res.ok) throw new Error("Error al obtener reportes");
        const data = await res.json();
        setReports(data);
      } catch (err) {
        console.error(err);
        alert("No se pudieron cargar los reportes desde el servidor.");
      } finally {
        setLoadingReports(false);
      }
    };

    fetchReports();
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.type || !formData.description || !formData.location) {
      alert("Por favor completa al menos: tipo, descripción y ubicación.");
      return;
    }

    try {
      setFormLoading(true);

      const payload = {
        ...formData,
        // fuente por ahora siempre "propio"
        source: "propio",
      };

      const res = await fetch(API_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });

      if (!res.ok) {
        throw new Error("Error al enviar reporte");
      }

      const savedReport = await res.json();

      setReports((prev) => [savedReport, ...prev]);

      alert("Reporte registrado en el servidor.");

      setFormData({
        type: "",
        description: "",
        location: "",
        contact: "",
        priority: "media",
        zone: "",
      });
      setView("home");
    } catch (err) {
      console.error(err);
      alert("Hubo un problema al enviar el reporte.");
    } finally {
      setFormLoading(false);
    }
  };

  const renderHome = () => (
    <main
      style={{
        flex: 1,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        padding: "2rem 1rem 3rem",
        maxWidth: "980px",
        margin: "0 auto",
      }}
    >
      {/* HERO */}
      <section
        style={{
          width: "100%",
          textAlign: "center",
          marginBottom: "2.5rem",
        }}
      >
        <h1
          style={{
            color: COLORS.red,
            fontSize: "2.4rem",
            marginBottom: "0.5rem",
          }}
        >
          ¡BALBOA ALERTA ESTÁ VIVO!
        </h1>

        <p
          style={{
            color: COLORS.darkText,
            maxWidth: "520px",
            fontSize: "1rem",
            margin: "0 auto 2rem",
          }}
        >
          Vecinos organizados reportando basura, daños, riesgos y problemas en
          tiempo real. Un distrito más limpio, más seguro, más nuestro.
        </p>

        <button
          style={{
            padding: "1rem 2.5rem",
            fontSize: "1.2rem",
            fontWeight: "bold",
            borderRadius: "999px",
            border: "none",
            backgroundColor: COLORS.red,
            color: COLORS.white,
            cursor: "pointer",
            boxShadow: "0 4px 10px rgba(0,0,0,0.15)",
          }}
          onClick={() => setView("report")}
        >
          Reportar incidencia
        </button>
      </section>

      {/* LISTA DE REPORTES REALES (desde backend) */}
      <section
        style={{
          width: "100%",
          backgroundColor: COLORS.white,
          borderRadius: "12px",
          boxShadow: "0 4px 16px rgba(0,0,0,0.08)",
          padding: "1.5rem 1.4rem",
          borderTop: `4px solid ${COLORS.gold}`,
        }}
      >
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            marginBottom: "1rem",
            alignItems: "center",
          }}
        >
          <h2
            style={{
              margin: 0,
              fontSize: "1.2rem",
              color: COLORS.darkText,
            }}
          >
            Reportes recientes
          </h2>
          <span
            style={{
              fontSize: "0.85rem",
              color: "#555",
            }}
          >
            {loadingReports
              ? "Cargando..."
              : reports.length === 0
              ? "Aún no hay reportes"
              : `${reports.length} reporte(s) registrados`}
          </span>
        </div>

        {loadingReports ? (
          <p style={{ fontSize: "0.9rem", color: "#666" }}>
            Obteniendo información del servidor...
          </p>
        ) : reports.length === 0 ? (
          <p
            style={{
              fontSize: "0.9rem",
              color: "#666",
            }}
          >
            Cuando envíes tu primer reporte, aparecerá aquí con tipo, ubicación,
            prioridad y zona.
          </p>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: "0.9rem" }}>
            {reports.map((r) => (
              <div
                key={r.id}
                style={{
                  border: `1px solid #e0e0e0`,
                  borderLeft: `4px solid ${COLORS.red}`,
                  borderRadius: "8px",
                  padding: "0.7rem 0.8rem",
                  backgroundColor: "#fafafa",
                }}
              >
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    marginBottom: "0.3rem",
                    alignItems: "center",
                  }}
                >
                  <strong style={{ color: COLORS.red, fontSize: "0.95rem" }}>
                    {r.type}
                  </strong>
                  <span
                    style={{
                      fontSize: "0.75rem",
                      color: "#666",
                    }}
                  >
                    {formatDate(r.createdAt)}
                  </span>
                </div>

                {/* Prioridad + estado */}
                <div
                  style={{
                    display: "flex",
                    gap: "0.5rem",
                    marginBottom: "0.3rem",
                    fontSize: "0.8rem",
                    alignItems: "center",
                  }}
                >
                  <span
                    style={{
                      padding: "0.15rem 0.5rem",
                      borderRadius: "999px",
                      backgroundColor: getPriorityColor(r.priority),
                      color: "#fff",
                      fontWeight: "bold",
                    }}
                  >
                    Prioridad: {getPriorityLabel(r.priority)}
                  </span>
                  <span
                    style={{
                      padding: "0.15rem 0.5rem",
                      borderRadius: "999px",
                      border: "1px solid #ccc",
                      color: "#444",
                    }}
                  >
                    Estado: {r.status || "nuevo"}
                  </span>
                </div>

                <div
                  style={{
                    fontSize: "0.85rem",
                    color: COLORS.darkText,
                    marginBottom: "0.3rem",
                  }}
                >
                  {r.description}
                </div>

                <div
                  style={{
                    fontSize: "0.8rem",
                    color: "#555",
                  }}
                >
                  <strong>Ubicación:</strong> {r.location}
                </div>

                {r.zone && (
                  <div
                    style={{
                      fontSize: "0.8rem",
                      color: "#555",
                      marginTop: "0.2rem",
                    }}
                  >
                    <strong>Zona:</strong> {r.zone}
                  </div>
                )}

                {r.contact && (
                  <div
                    style={{
                      fontSize: "0.8rem",
                      color: "#555",
                      marginTop: "0.2rem",
                    }}
                  >
                    <strong>Contacto:</strong> {r.contact}
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </section>
    </main>
  );

  const renderForm = () => (
    <main
      style={{
        flex: 1,
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        padding: "2rem 1rem",
      }}
    >
      <div
        style={{
          width: "100%",
          maxWidth: "540px",
          backgroundColor: COLORS.white,
          borderRadius: "12px",
          boxShadow: "0 4px 16px rgba(0,0,0,0.1)",
          padding: "1.8rem 1.6rem",
          borderTop: `5px solid ${COLORS.red}`,
        }}
      >
        <h2
          style={{
            marginTop: 0,
            marginBottom: "0.5rem",
            color: COLORS.red,
          }}
        >
          Nuevo reporte ciudadano
        </h2>
        <p
          style={{
            marginTop: 0,
            marginBottom: "1.2rem",
            fontSize: "0.9rem",
            color: COLORS.darkText,
          }}
        >
          Describe el problema con claridad. Esta información será la base para
          priorizar acciones en el territorio.
        </p>

        <form onSubmit={handleSubmit}>
          {/* Tipo */}
          <div style={{ marginBottom: "1rem" }}>
            <label
              style={{ display: "block", marginBottom: "0.3rem", fontSize: "0.9rem" }}
            >
              Tipo de incidencia <span style={{ color: COLORS.red }}>*</span>
            </label>
            <select
              name="type"
              value={formData.type}
              onChange={handleChange}
              style={{
                width: "100%",
                padding: "0.6rem",
                borderRadius: "6px",
                border: "1px solid #ccc",
              }}
            >
              <option value="">Selecciona una opción</option>
              {INCIDENT_TYPES.map((t) => (
                <option key={t} value={t}>
                  {t}
                </option>
              ))}
            </select>
          </div>

          {/* PRIORIDAD */}
          <div style={{ marginBottom: "1rem" }}>
            <label
              style={{ display: "block", marginBottom: "0.3rem", fontSize: "0.9rem" }}
            >
              Prioridad <span style={{ color: COLORS.red }}>*</span>
            </label>
            <select
              name="priority"
              value={formData.priority}
              onChange={handleChange}
              style={{
                width: "100%",
                padding: "0.6rem",
                borderRadius: "6px",
                border: "1px solid #ccc",
              }}
            >
              {PRIORITY_OPTIONS.map((p) => (
                <option key={p.value} value={p.value}>
                  {p.label}
                </option>
              ))}
            </select>
          </div>

          {/* Descripción */}
          <div style={{ marginBottom: "1rem" }}>
            <label
              style={{ display: "block", marginBottom: "0.3rem", fontSize: "0.9rem" }}
            >
              Descripción del problema{" "}
              <span style={{ color: COLORS.red }}>*</span>
            </label>
            <textarea
              name="description"
              value={formData.description}
              onChange={handleChange}
              rows={4}
              placeholder="Ejemplo: Basura acumulada desde hace 3 semanas, genera malos olores y moscas."
              style={{
                width: "100%",
                padding: "0.6rem",
                borderRadius: "6px",
                border: "1px solid #ccc",
                resize: "vertical",
              }}
            />
          </div>

          {/* Ubicación */}
          <div style={{ marginBottom: "1rem" }}>
            <label
              style={{ display: "block", marginBottom: "0.3rem", fontSize: "0.9rem" }}
            >
              Ubicación aproximada{" "}
              <span style={{ color: COLORS.red }}>*</span>
            </label>
            <input
              type="text"
              name="location"
              value={formData.location}
              onChange={handleChange}
              placeholder="Calle, referencia cercana, barrio."
              style={{
                width: "100%",
                padding: "0.6rem",
                borderRadius: "6px",
                border: "1px solid #ccc",
              }}
            />
          </div>

          {/* Zona */}
          <div style={{ marginBottom: "1rem" }}>
            <label
              style={{ display: "block", marginBottom: "0.3rem", fontSize: "0.9rem" }}
            >
              Zona / Sector (ej. Barrio Balboa - Calle 3, cerca de la iglesia)
            </label>
            <input
              type="text"
              name="zone"
              value={formData.zone}
              onChange={handleChange}
              placeholder="Barrio o sector donde ocurre el problema."
              style={{
                width: "100%",
                padding: "0.6rem",
                borderRadius: "6px",
                border: "1px solid #ccc",
              }}
            />
          </div>

          {/* Contacto */}
          <div style={{ marginBottom: "1.4rem" }}>
            <label
              style={{ display: "block", marginBottom: "0.3rem", fontSize: "0.9rem" }}
            >
              Contacto (opcional)
            </label>
            <input
              type="text"
              name="contact"
              value={formData.contact}
              onChange={handleChange}
              placeholder="Nombre o teléfono para aclaraciones (opcional)."
              style={{
                width: "100%",
                padding: "0.6rem",
                borderRadius: "6px",
                border: "1px solid #ccc",
              }}
            />
          </div>

          {/* Botones */}
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              gap: "0.8rem",
            }}
          >
            <button
              type="button"
              onClick={() => setView("home")}
              style={{
                flex: 1,
                padding: "0.7rem 1rem",
                borderRadius: "999px",
                border: `1px solid ${COLORS.red}`,
                backgroundColor: COLORS.white,
                color: COLORS.red,
                fontWeight: "bold",
                cursor: "pointer",
              }}
              disabled={formLoading}
            >
              Cancelar
            </button>
            <button
              type="submit"
              style={{
                flex: 1,
                padding: "0.7rem 1rem",
                borderRadius: "999px",
                border: "none",
                backgroundColor: COLORS.red,
                color: COLORS.white,
                fontWeight: "bold",
                cursor: "pointer",
                opacity: formLoading ? 0.7 : 1,
              }}
              disabled={formLoading}
            >
              {formLoading ? "Enviando..." : "Enviar reporte"}
            </button>
          </div>
        </form>
      </div>
    </main>
  );

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        flexDirection: "column",
        backgroundColor: COLORS.lightGray,
        fontFamily: "Arial, sans-serif",
      }}
    >
      {/* HEADER */}
      <header
        style={{
          backgroundColor: COLORS.white,
          borderBottom: `3px solid ${COLORS.red}`,
          padding: "1rem 2rem",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
        }}
      >
        <div
          style={{
            fontWeight: "bold",
            fontSize: "1.4rem",
            color: COLORS.red,
          }}
        >
          BALBOA ALERTA
        </div>
        <div
          style={{
            fontSize: "0.9rem",
            color: COLORS.darkText,
            borderLeft: `3px solid ${COLORS.gold}`,
            paddingLeft: "0.7rem",
          }}
        >
          Plataforma ciudadana de reportes locales
        </div>
      </header>

      {view === "home" ? renderHome() : renderForm()}

      {/* FOOTER */}
      <footer
        style={{
          backgroundColor: COLORS.white,
          borderTop: `2px solid ${COLORS.gold}`,
          padding: "0.7rem 1.5rem",
          fontSize: "0.8rem",
          color: COLORS.darkText,
          textAlign: "center",
        }}
      >
        Balboa Alerta · Iniciativa ciudadana para La Chorrera
      </footer>
    </div>
  );
}

export default App;
